def solve(arr, k):
    buckets = {}
    for v in arr:
        r = v % k
        buckets.setdefault(r, 0)
        buckets[r] += 1
    seen = set()
    for r in list(buckets.keys()):
        if r in seen:
            continue
        comp = (k - r) % k
        seen.add(r)
        seen.add(comp)
        if r == comp:
            if buckets[r] % 2 != 0:
                return False
        else:
            if buckets.get(r, 0) != buckets.get(comp, 0):
                return False
    return True


class Solution:
    def canArrange(self, arr, k):
        return solve(arr, k)

