from collections import Counter


class Solution:
    def canArrange(self, arr: List[int], k: int) -> bool:
        cnt = Counter(x % k for x in arr)
        for r, c in cnt.items():
            if r == 0:
                if c % 2 != 0:
                    return False
            else:
                if cnt.get(k - r, 0) != c:
                    return False
        return True

